ALTER TABLE public.fs_decisions RENAME COLUMN date_mandatement TO date_demande_paiement; ALTER TABLE public.fs_decisions RENAME COLUMN numero_mandat TO numero_demande_paiement; ALTER TABLE public.fs_decisions ADD COLUMN IF NOT EXISTS extinction_creance_dp boolean NOT NULL DEFAULT false, ADD COLUMN IF NOT EXISTS compte_creance_famille text NOT NULL DEFAULT '411200', ADD COLUMN IF NOT EXISTS deliberation_ca_id uuid, ADD COLUMN IF NOT EXISTS bordereau_dp_url text, ADD COLUMN IF NOT EXISTS courrier_complement_url text, ADD COLUMN IF NOT EXISTS courrier_refus_url text; CREATE TABLE IF NOT EXISTS public.fs_deliberations_ca (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), establishment_id uuid NOT NULL, numero text NOT NULL, date_ca date NOT NULL, annee_scolaire text NOT NULL, type_fonds text NOT NULL, plafond_aide_individuelle numeric(10,2), plafond_cumul_annuel numeric(10,2), criteres_attribution text, pieces_obligatoires text[], pdf_url text, user_id uuid NOT NULL, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now()); ALTER TABLE public.fs_deliberations_ca ENABLE ROW LEVEL SECURITY; CREATE POLICY "Users access their establishment deliberations" ON public.fs_deliberations_ca FOR ALL USING (public.user_has_establishment_access(auth.uid(), establishment_id)) WITH CHECK (public.user_has_establishment_access(auth.uid(), establishment_id)); CREATE TRIGGER trg_fs_deliberations_ca_updated BEFORE UPDATE ON public.fs_deliberations_ca FOR EACH ROW EXECUTE FUNCTION public.update_updated_at_column(); CREATE TABLE IF NOT EXISTS public.fs_commission_convocations (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), establishment_id uuid NOT NULL, commission_id uuid NOT NULL REFERENCES public.fs_commissions(id) ON DELETE CASCADE, date_envoi date NOT NULL DEFAULT CURRENT_DATE, membres_convoques jsonb NOT NULL DEFAULT '[]'::jsonb, ordre_du_jour text, pdf_url text, user_id uuid NOT NULL, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now()); ALTER TABLE public.fs_commission_convocations ENABLE ROW LEVEL SECURITY; CREATE POLICY "Users access their establishment convocations" ON public.fs_commission_convocations FOR ALL USING (public.user_has_establishment_access(auth.uid(), establishment_id)) WITH CHECK (public.user_has_establishment_access(auth.uid(), establishment_id)); CREATE TRIGGER trg_fs_commission_convocations_updated BEFORE UPDATE ON public.fs_commission_convocations FOR EACH ROW EXECUTE FUNCTION public.update_updated_at_column(); ALTER TABLE public.fs_commissions ADD COLUMN IF NOT EXISTS pv_anonymise_url text, ADD COLUMN IF NOT EXISTS pv_integral_url text, ADD COLUMN IF NOT EXISTS convocation_envoyee boolean NOT NULL DEFAULT false; CREATE TABLE IF NOT EXISTS public.fs_journal_acces (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), establishment_id uuid NOT NULL, user_id uuid NOT NULL, user_name text, type_ressource text NOT NULL, ressource_id uuid NOT NULL, action text NOT NULL, details jsonb DEFAULT '{}'::jsonb, ip_adresse text, created_at timestamptz NOT NULL DEFAULT now()); ALTER TABLE public.fs_journal_acces ENABLE ROW LEVEL SECURITY; CREATE POLICY "Users read their establishment journal" ON public.fs_journal_acces FOR SELECT USING (public.user_has_establishment_access(auth.uid(), establishment_id)); CREATE POLICY "Users log to their establishment journal" ON public.fs_journal_acces FOR INSERT WITH CHECK (auth.uid() = user_id AND public.user_has_establishment_access(auth.uid(), establishment_id)); CREATE TRIGGER trg_fs_journal_acces_user_name BEFORE INSERT ON public.fs_journal_acces FOR EACH ROW EXECUTE FUNCTION public.set_audit_trail_user_name(); ALTER TABLE public.fs_decisions ADD CONSTRAINT fs_decisions_deliberation_ca_fk FOREIGN KEY (deliberation_ca_id) REFERENCES public.fs_deliberations_ca(id) ON DELETE SET NULL; CREATE INDEX IF NOT EXISTS idx_fs_deliberations_ca_etab ON public.fs_deliberations_ca(establishment_id, annee_scolaire); CREATE INDEX IF NOT EXISTS idx_fs_commission_convocations_commission ON public.fs_commission_convocations(commission_id); CREATE INDEX IF NOT EXISTS idx_fs_journal_acces_etab_date ON public.fs_journal_acces(establishment_id, created_at DESC); CREATE INDEX IF NOT EXISTS idx_fs_decisions_deliberation ON public.fs_decisions(deliberation_ca_id);